#!/usr/bin/env python3
import matplotlib.pyplot as plt
import numpy as np
from collections import defaultdict
import os
import json

# Create graphs directory if it doesn't exist
script_dir = os.path.dirname(os.path.abspath(__file__))
graphs_dir = os.path.join(script_dir, 'graphs')
os.makedirs(graphs_dir, exist_ok=True)

# Load data from accuracy_data.json (generated by run_mock_pipeline.py)
data_file = os.path.join(script_dir, 'accuracy_data.json')
if os.path.exists(data_file):
    with open(data_file, 'r') as f:
        data = json.load(f)
    print(f"Loaded {len(data)} entries from {data_file}")
else:
    print(f"Error: {data_file} not found. Run run_mock_pipeline.py first to generate benchmark data.")
    exit(1)

# Check if timing data exists
# The pipeline collects: load, prepare, extract, tag, verify, fix, consolidate, total
timing_keys = ['load', 'prepare', 'extract', 'tag', 'verify', 'fix', 'consolidate', 'total', 'load_duration', 'total_duration']
timing_data_exists = any(k in entry for entry in data for k in timing_keys)

if not timing_data_exists:
    print("\nWARNING: No timing data found in accuracy_data.json.")
    print("The benchmark run did not collect timing information per pipeline step.")
    print("Timing graphs cannot be generated.")
    print("\nTo collect timing data, run the full pipeline test with a version")
    print("that includes timing collection (e.g., with --verbose flag or updated test suite).")
    exit(0)

# Define batch size labels
batch_order = [
    'Single Batch', 'Double Batch', 'Triple Batch', 'Quadruple Batch',
    'Quintuple Batch', 'Sextuple Batch', 'Septuple Batch', 'Octuple Batch',
    'Nonuple', 'Decuple', 'Quindecuple', 'Vigintuple'
]

# Map batch names to numeric values for x-axis (number of items per batch)
batch_to_num = {
    'Single Batch': 1, 'Double Batch': 2, 'Triple Batch': 3, 'Quadruple Batch': 4,
    'Quintuple Batch': 5, 'Sextuple Batch': 6, 'Septuple Batch': 7, 'Octuple Batch': 8,
    'Nonuple': 9, 'Decuple': 10, 'Quindecuple': 15, 'Vigintuple': 20
}

# Define steps to plot (matching actual pipeline step names in accuracy_data.json)
steps = [
    ('load', 'Step 1: Data Loading'),
    ('extract', 'Step 2: Fault Extraction'),
    ('verify', 'Step 3: Timestamp Verification'),
    ('fix', 'Step 4: Timestamp Correction'),
    ('consolidate', 'Step 5: Final Verification'),
    ('total', 'Total Processing Time')
]

def analyze_batch_data(data, step_key):
    """Group data by batch size and calculate mean + std for each step."""
    batch_times = defaultdict(list)
    
    for entry in data:
        # Skip aggregated entries (they don't have timing data)
        if entry.get('is_aggregated'):
            continue
        
        # Use batch_size (numeric) instead of batch (string name)
        batch_size = entry.get('batch_size')
        if batch_size is not None and step_key in entry:
            batch_times[batch_size].append(entry[step_key])
    
    # Sort by batch size
    batch_sizes = sorted(batch_times.keys())
    means = [np.mean(batch_times[b]) for b in batch_sizes]
    stds = [np.std(batch_times[b]) for b in batch_sizes]
    
    return batch_sizes, means, stds

# Create individual graphs for each step
for step_key, step_title in steps:
    batch_sizes, means, stds = analyze_batch_data(data, step_key)
    
    if not batch_sizes:
        print(f"\nNo timing data found for {step_title}. Skipping graph.")
        continue
    
    fig, ax = plt.subplots(figsize=(10, 6))
    
    ax.errorbar(batch_sizes, means, yerr=stds, fmt='-o', capsize=5,
                linewidth=2, markersize=8, ecolor='red', elinewidth=2,
                label=step_title)
    
    ax.set_xlabel('Batch Size (items per batch)', fontsize=11)
    ax.set_ylabel('Processing Time (seconds)', fontsize=11)
    ax.set_title(f'{step_title}\n4 Parallel Workers | qwen3-122B-A10B\n2026-05-01 to 2026-05-05', fontsize=10)
    ax.set_xticks(batch_sizes)
    ax.grid(True, alpha=0.3)
    ax.set_ylim(bottom=0)
    ax.legend()
    
    # Create filename from step key
    filename = f'batching_time_{step_key}.png'
    output_path = os.path.join(graphs_dir, filename)
    
    plt.savefig(output_path, dpi=150, bbox_inches='tight')
    print(f"Graph saved as '{output_path}'")
    plt.close()

print(f"\nAll {len(steps)} graphs saved in '{graphs_dir}' directory.")